<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\Project;use App\Support\CurrentWorkspace;use Illuminate\Http\Request;use Illuminate\Validation\Rule;
class ProjectController extends Controller{use Concerns;public function index(CurrentWorkspace $cw){$w=$this->ws($cw);return view('tenant.projects.index',['projects'=>Project::latest()->paginate(20),'users'=>$w->users()->get()]);}public function store(Request $r,CurrentWorkspace $cw){$this->requirePerm('tenant.tasks.create');$w=$this->ws($cw);$d=$r->validate(['name'=>'required|string|max:255','code'=>'nullable|string|max:50','client_name'=>'nullable|string|max:255','description'=>'nullable|string','project_manager_id'=>['nullable',Rule::exists('workspace_user','user_id')->where('workspace_id',$w->id)],'status'=>'required|in:active,hold,completed,archived','start_date'=>'nullable|date','end_date'=>'nullable|date|after_or_equal:start_date']);Project::create($d+['workspace_id'=>$w->id]);return back()->with('status','Project created.');}}
